    category: "Outdoors",
    categoryId: "outdoors",
    ownerName: "Lisa Anderson",
    status: "available" as const,
  },
];

// TODO: remove mock functionality
const mockCategories: Category[] = [
  { id: "outdoors", name: "Outdoors" },
  { id: "tools", name: "Tools" },
  { id: "sports", name: "Sports" },
  { id: "tech", name: "Tech" },
  { id: "home", name: "Home" },
];

export default function HomePage() {
  const [searchQuery, setSearchQuery] = useState("");
  const [selectedCategory, setSelectedCategory] = useState<string | null>(null);
  const [filterStatus, setFilterStatus] = useState<string | null>(null);
  const [selectedItem, setSelectedItem] = useState<typeof mockItems[0] | null>(null);
  const [showBorrowModal, setShowBorrowModal] = useState(false);

  const filteredItems = mockItems.filter((item) => {
    const matchesSearch = 
      searchQuery === "" ||
      item.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
      item.description.toLowerCase().includes(searchQuery.toLowerCase()) ||
      item.ownerName.toLowerCase().includes(searchQuery.toLowerCase());

    if (!matchesSearch) return false;
    if (selectedCategory && item.categoryId !== selectedCategory) return false;
    if (filterStatus && item.status !== filterStatus) return false;
    return true;
  });

  const handleRequestBorrow = () => {
    setShowBorrowModal(true);
  };

  const handleBorrowSubmit = (data: { message: string; date: Date | undefined }) => {
    console.log("Borrow request submitted:", data);
  };

  return (
    <div className="min-h-screen bg-background pb-20 lg:pb-0">
      <TopNav
        userName="John Doe"
        notificationCount={2}
        onProfileClick={() => console.log("Profile clicked")}
        onNotificationsClick={() => console.log("Notifications clicked")}
      />

      <main className="container mx-auto px-4 py-6 max-w-7xl">
        <div className="mb-6">
          <div className="flex items-center justify-between mb-4">
            <div>
              <h2 className="text-3xl font-bold font-sans mb-1" style={{ fontFamily: "DM Sans, sans-serif" }}>
                What's Available
              </h2>
              <p className="text-muted-foreground">
                Discover what your friends are sharing
              </p>
            </div>
            <Button
              variant="outline"
              size="sm"
              className="gap-2"
              onClick={() => {
                const statuses = [null, "available", "borrowed", "yours"];
                const currentIndex = statuses.indexOf(filterStatus);
                const nextIndex = (currentIndex + 1) % statuses.length;
                setFilterStatus(statuses[nextIndex]);
                console.log("Filter:", statuses[nextIndex]);
              }}
              data-testid="button-filter"
            >
              <Filter className="h-4 w-4" />
              {filterStatus === "available" && "Available"}
              {filterStatus === "borrowed" && "Borrowed"}
              {filterStatus === "yours" && "Your Items"}
              {!filterStatus && "All"}
            </Button>
          </div>
          <div className="mb-4">
            <SearchBar
              value={searchQuery}
              onChange={setSearchQuery}
              placeholder="Search items, owners, or categories..."
            />
          </div>
          <CategoryFilter
            categories={mockCategories}
            selectedCategory={selectedCategory}
            onSelectCategory={setSelectedCategory}
          />
        </div>

        {searchQuery && (
          <div className="mb-4">
            <p className="text-sm text-muted-foreground">
              Found {filteredItems.length} {filteredItems.length === 1 ? "item" : "items"}
              {searchQuery && ` matching "${searchQuery}"`}
            </p>
          </div>
        )}

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {filteredItems.map((item) => (
            <ItemCard
              key={item.id}
              {...item}
              onClick={() => setSelectedItem(item)}
            />
          ))}
        </div>

        {filteredItems.length === 0 && (
          <div className="text-center py-12">
            <p className="text-muted-foreground mb-4">
              {searchQuery ? `No items found for "${searchQuery}"` : "No items found. Try adjusting your filters."}
            </p>
            <Button variant="outline" onClick={() => {
              setSearchQuery("");
              setSelectedCategory(null);
              setFilterStatus(null);
            }}>
              Clear {searchQuery ? "Search and Filters" : "Filters"}
            </Button>
          </div>
        )}
      </main>

      <BottomNav />

      <ItemDetailModal
        open={!!selectedItem}
        onOpenChange={(open) => !open && setSelectedItem(null)}
        item={selectedItem}
        onRequestBorrow={handleRequestBorrow}
        onMessage={(id) => console.log("Message item:", id)}
        onViewProfile={(id) => console.log("View profile:", id)}
      />

      {selectedItem && (
        <BorrowRequestModal
          open={showBorrowModal}
          onOpenChange={setShowBorrowModal}
          itemName={selectedItem.name}
          onSubmit={handleBorrowSubmit}
        />
      )}
    </div>
  );
}

